<template>
  <div class="mx-auto max-w-7xl"><section class="mb-6 flex flex-wrap items-end justify-between gap-4"><div><p class="text-sm font-semibold text-primary">INSTRUCTOR TOOLS</p><h2 class="mt-1 text-2xl font-semibold tracking-tight sm:text-3xl">Promotion eligibility</h2><p class="mt-2 text-sm text-slate-500">A practical review queue—not an automatic promotion decision.</p></div><div class="flex gap-2"><UButton :color="filter === 'ready' ? 'primary' : 'neutral'" :variant="filter === 'ready' ? 'solid' : 'soft'" @click="filter = filter === 'ready' ? 'all' : 'ready'">{{ filter === 'ready' ? 'Showing ready' : 'Ready only' }}</UButton></div></section><UAlert class="mb-5" color="primary" variant="subtle" :title="`Readiness rule: ${data?.threshold.attendance || 80}% attendance across at least ${data?.threshold.classes || 4} classes in the last ${data?.threshold.periodDays || 90} days`" description="Instructors retain the final assessment decision; the queue also flags unpaid grading attempts." /><UCard><div v-if="pending" class="space-y-3"><USkeleton v-for="i in 6" :key="i" class="h-14" /></div><div v-else-if="visible.length" class="overflow-x-auto"><table class="min-w-[980px] w-full text-sm"><thead class="border-b text-left text-xs uppercase tracking-wide text-slate-400"><tr><th class="p-3">Student</th><th class="p-3">Dojo</th><th class="p-3">Progression</th><th class="p-3">Recent attendance</th><th class="p-3">Last grading</th><th class="p-3">Review status</th><th class="p-3"></th></tr></thead><tbody><tr v-for="item in visible" :key="item.studentId" class="border-b border-slate-100 dark:border-slate-800"><td class="p-3 font-medium">{{ item.studentName }}</td><td class="p-3">{{ item.dojoName }}</td><td class="p-3"><p>{{ item.currentRank }}</p><p class="text-xs text-slate-500">Next: {{ item.nextRank || '—' }}</p></td><td class="p-3"><span :class="item.attendanceRate >= data.threshold.attendance ? 'text-emerald-600' : 'text-amber-600'" class="font-medium">{{ item.attendanceRate }}%</span><p class="text-xs text-slate-500">{{ item.classesRecorded }} classes</p></td><td class="p-3">{{ item.lastGradingDate ? formatDate(item.lastGradingDate) : 'No grading recorded' }}</td><td class="p-3"><UBadge :color="item.eligible ? 'success' : 'warning'" variant="subtle">{{ item.eligible ? 'Ready for review' : 'Needs review' }}</UBadge><p v-if="item.reasons.length" class="mt-1 max-w-64 text-xs text-slate-500">{{ item.reasons.join(' · ') }}</p></td><td class="p-3 text-right"><UButton :to="`/students/${item.studentId}`" size="xs" color="neutral" variant="soft">Open student</UButton></td></tr></tbody></table></div><div v-else class="py-12 text-center text-sm text-slate-500">No students match this view.</div></UCard></div>
</template>
<script setup lang="ts">
definePageMeta({ middleware: 'auth' }); const filter = ref<'all' | 'ready'>('all'); const { data, pending } = await useFetch<any>('/api/grading-exams/eligibility'); const visible = computed(() => (data.value?.candidates || []).filter((item:any) => filter.value === 'all' || item.eligible)); const formatDate = (value:string) => new Date(value).toLocaleDateString('en-IN', { dateStyle: 'medium' })
</script>
